import os
import json
from azure.storage.blob import BlobServiceClient, BlobClient

# Load environment variables
AZURE_STORAGE_CONNECTION_STRING = os.environ['AZURE_STORAGE_CONNECTION_STRING']
MODEL_PATH = os.environ['MODEL_PATH']

def main():
    # Create Azure Blob Storage client
    blob_service_client = BlobServiceClient.from_connection_string(AZURE_STORAGE_CONNECTION_STRING)
    container_name = 'models'
    model_blob_client = blob_service_client.get_blob_client(container=container_name, blob=MODEL_PATH)

    # Fetch latest model version
    models = list(blob_service_client.list_blobs(container_name))
    model_version = len(models) - 1
    print(f'Fetched model version {model_version}')

    # Load model from Azure Blob Storage
    model = json.loads(model_blob_client.download_blob().readall())

    # Print model information
    print('Model loaded:', model)